sp_widget.client_script:
api.controller = function($scope) {
    var c = this;

    var shared = c.widget.options.shared;
    //console.log(JSON.stringify(shared));

    c.updateStatus = function(action) {
        c.data.action = action;
				c.data.sysid = c.data.sys_id; 

        c.server.update().then(function(response) {
            //console.log("Action:", action, "Response:", response);
				/*	var scope = $scope;

						while (scope && !scope.$dismiss) {
								scope = scope.$parent;
						}

						if (scope && scope.$dismiss) {
								scope.$dismiss(action);
						}
					//$scope.$close(); */

					closeModal($scope, {
                action: action,
								response:response,
                status: "success"
            });

        });
    };

	 closeModal=function($scope, data) {

		 shared.result=data;

   var scope = $scope;

    while (scope && !scope.$close) {
        scope = scope.$parent;
    }

    if (scope && scope.$close) {
        scope.$close(data); 
    } else {
        console.error("No $close found in scope chain");
    }
}
};

sp_widget.css:
.modal-body
{
 margin:5px;
  padding:5px;

}
.modal-container {
  background: #fff;
  border-radius: 10px;
  padding: 10px;
  max-width: 700px;
  margin: auto;
  box-shadow: 0 10px 30px rgba(0,0,0,0.1);
}

.modal-header h2 {
  font-size: 18px;
  font-weight: 600;
}

.modal-header p {
  font-size: 13px;
  color: #666;
}

.plan-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;
  background: #f9fafb;
  padding: 15px;
  border-radius: 8px;
  margin-top: 15px;
}

.col-span-2 {
  grid-column: span 2;
}

.plan-grid label {
  font-size: 12px;
  color: #666;
}

.value {
  font-weight: 600;
}

textarea {
  width: 100%;
  margin-top: 6px;
  padding: 8px;
  border-radius: 6px;
  border: 1px solid #ddd;
}

.timeline {
  margin-top: 20px;
  border-top: 1px solid #eee;
  padding-top: 10px;
}

.timeline-item {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  margin-top: 5px;
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
}

.gray { background: gray; }
.yellow { background: #facc15; }
.green { background: #22c55e; }

.modal-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 20px;
}

.btn {
  padding: 8px 14px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
}

.btn.secondary {
  background: #f3f4f6;
}

.btn.reject {
  background: #fee2e2;
  color: #b91c1c;
}

.btn.primary {
  background: #2563eb;
  color: #fff;
}

sp_widget.script:
(function() {

    data.plan = {};

    // -----------------------------
    // TABLE & SYS_ID SETUP
    // -----------------------------
    if (input && input.table) 
        data.table = input.table;
    else if (options && options.table) 
        data.table = options.table;
    else 
        data.table = "x_ctans_incentnow_quota";

    if (input && input.sysid) 
        data.sys_id = input.sysid;
    else if (options && options.sys_id) 
        data.sys_id = options.sys_id;
    else 
        data.sys_id = "";

    // -----------------------------
    // FETCH RECORD
    // -----------------------------
    var grTab = new GlideRecordSecure(data.table);
    if (grTab.get(data.sys_id)) {

        data.plan.sys_id = grTab.getUniqueValue();

        data.planFields = [
            { label: "Quota Name", field: "name", col: 1 },
						{ label: "Fiscal Year", field: "fiscal_year", col: 1 },
            { label: "Frequency", field: "quota_frequency", col: 1 },
						{ label: "Quota Value", field: "quota_metric", col: 1 },
            { label: "Created By", field: "sys_created_by", col: 1 },
            { label: "Description", field: "description", col: 2 }
        ];

        data.planFields.forEach(function(f) {
            data.plan[f.field] = grTab.getDisplayValue(f.field);
        });

        data.timelineFields = [
            {
                label: "Created",
                field: "sys_created_on",
                userField: "sys_created_by",
                color: "gray"
            }
        ];

        data.timelineFields.forEach(function(t) {
            t.date = grTab.getDisplayValue(t.field);
            t.user = grTab.getDisplayValue(t.userField);
        });
    }

    // -----------------------------
    // ACTION HANDLING
    // -----------------------------
    if (input && input.action) {
			data.query=input.action;

        var user = gs.getUser().getID();

        if (input.action == "approved" || input.action == "rejected") {
            performApproval(input.action, user);
        } 
        else if (input.action == "closed") {
            data.message = "Closed action not supported for approvals";
        }
    }

    // -----------------------------
    // APPROVAL FUNCTION
    // -----------------------------
    function performApproval(action, user) {

        var gApproval = new GlideRecordSecure('sysapproval_approver');

        gApproval.addQuery('document_id', data.sys_id);
        gApproval.addQuery('approver', user);
        gApproval.addQuery('state', 'requested'); // IMPORTANT

        gApproval.orderByDesc('sys_created_on');
        gApproval.query();
			data.query=gApproval.getEncodedQuery();

        if (gApproval.next()) {
            gApproval.setValue('state', action);
            gApproval.update();

            data.status = "success";
            data.message = "Approval " + action + " successfully";
        } else {
            data.status = "error";
            data.message = "No pending approval found for you";
            //data.message("You are not part of this approval group.");
        }
    }

})();
